public CreateOrderResponse createOrder(CreateOrderRequest request) {
    if (request.getCustomerId().isEmpty()) {
        throw Status.INVALID_ARGUMENT
            .withDescription("customer_id is required")
            .asRuntimeException();
    }
    if (request.getItemsList().isEmpty()) {
        throw Status.INVALID_ARGUMENT
            .withDescription("at least one item is required")
            .asRuntimeException();
    }
    Order order = orderService.create(
        request.getCustomerId(),
        request.getItemsList());
    return CreateOrderResponse.newBuilder().setOrder(order).build();
}
